export type Codepoint = {
    hex: number[];
    category: string;
    /** ISO 15924 script (e.g. "Latn"). Undefined for Common/Inherited/Unknown
     *  codepoints and multi-codepoint emoji sequences. */
    script: string | undefined;
    emoji: { group: string; subgroup: string } | undefined;
};

let codepoints: Codepoint[] | undefined = undefined;

export async function getCodepoints(): Promise<Codepoint[]> {
    if (codepoints !== undefined) return codepoints;

    // Generated by src/unicode/compress.ts. Run `npm run codes` to refresh.
    // Lines are: "<hex>;<category>;<script>" or
    // "<hex>;<category>;<script>;<emoji-group>;<emoji-subgroup>".
    // <script> may be empty for codepoints with no real script
    // (Common/Inherited/Unknown).
    const codesTxt: string = await fetch('/unicode/codes.txt').then((r) =>
        r.text(),
    );

    codepoints = [];
    for (const entry of codesTxt.split('\n')) {
        if (!entry) continue;
        const [code, category, script, group, subgroup] = entry.split(';');
        if (!code || !category) continue;
        codepoints.push({
            hex: code.split(' ').map((c) => parseInt(c, 16)),
            category,
            script: script && script.length > 0 ? script : undefined,
            emoji:
                group && subgroup
                    ? {
                          group,
                          subgroup,
                      }
                    : undefined,
        });
    }

    // Sort by category, group, then subgroup, preserving file order within
    // each subgroup. Codepoints no longer carry names, so we drop the name-
    // based tiebreaker that used to keep results deterministic.
    codepoints.sort((a, b) => {
        if (a.category !== b.category)
            return a.category.localeCompare(b.category);
        if (a.emoji?.group !== b.emoji?.group)
            return (a.emoji?.group ?? '').localeCompare(b.emoji?.group ?? '');
        if (a.emoji?.subgroup !== b.emoji?.subgroup)
            return (a.emoji?.subgroup ?? '').localeCompare(
                b.emoji?.subgroup ?? '',
            );
        return 0;
    });

    return codepoints;
}

let scriptNames: Record<string, string> | undefined = undefined;

/** Load the ISO 15924 → English long-name map used to label scripts the
 *  picker surfaces but src/locale/Scripts.ts doesn't already provide a
 *  native-name label for. Generated by src/unicode/compress.ts; refresh via
 *  `npm run codes`. */
export async function getScripts(): Promise<Record<string, string>> {
    if (scriptNames !== undefined) return scriptNames;

    const scriptsTxt: string = await fetch('/unicode/scripts.txt').then((r) =>
        r.text(),
    );

    const map: Record<string, string> = {};
    for (const entry of scriptsTxt.split('\n')) {
        if (!entry) continue;
        const [iso, name] = entry.split(';');
        if (!iso || !name) continue;
        map[iso] = name;
    }
    scriptNames = map;
    return scriptNames;
}

/** Format a codepoint sequence the same way codes.txt does so it matches the
 * keys in the per-locale {locale}-emojis.json files: each codepoint as upper-
 * case hex, zero-padded to a minimum of 4 digits, joined by spaces. */
export function codepointKey(hex: number[]): string {
    return hex
        .map((cp) => cp.toString(16).toUpperCase().padStart(4, '0'))
        .join(' ');
}

export async function getEmoji() {
    return (await getCodepoints()).filter((point) => point.emoji !== undefined);
}

